import React, { useEffect } from "react";
import { Link } from "react-router-dom";
import { getAllProducts } from "../features/products/productSlice";
import { useDispatch, useSelector } from "react-redux";

const ProductAll = () => {
  const dispatch = useDispatch();
  const { product } = useSelector((state) => state.product);

  const RecommendedProducts = product.filter((product) =>
    product.tags?.some((tag) =>
      ["recommended", "Recommended"].includes(tag.toLowerCase()),
    ),
  );

  useEffect(() => {
    dispatch(getAllProducts());
  }, [dispatch]);

  if (RecommendedProducts.length === 0) return null;

  return (
    <div className="bg-white rounded-xl border border-gray-200 p-5 shadow-sm w-full">
      <div className="flex items-center gap-2 mb-4">
        <h2 className="text-[16px] font-bold text-gray-800">
          Elite <span className="text-blue-500">⭐</span> Selection Our Medical
          Catalog
        </h2>
      </div>

      <div className="flex space-x-4 overflow-x-auto pb-4 no-scrollbar">
        {RecommendedProducts.map((item) => (
          <div key={item._id} className="flex-shrink-0 w-[120px] group">
            <Link className="block" to={`/productdetails/${item._id}`}>
              <div className="aspect-square rounded-xl overflow-hidden bg-[#fdfdfd] mb-3 border border-gray-100 flex items-center justify-center p-3">
                <img
                  className="max-w-full max-h-full object-contain transition-all duration-500 group-hover:scale-110"
                  src={(() => {
                    const prodImages = Array.isArray(item?.images) ? item.images : (item?.images ? [item.images] : []);
                    const firstColorImages = Array.isArray(item?.colors?.[0]?.images) ? item.colors[0].images : (item?.colors?.[0]?.images ? [item.colors[0].images] : []);
                    return prodImages[0]?.secure_url || firstColorImages[0]?.secure_url || "https://res.cloudinary.com/dpkv77m87/image/upload/v1711200000/fallback_product_image.png";
                  })()}
                  alt={item.title}
                />
              </div>
              <div className="text-center">
                <div className="text-rose-500 font-bold text-[14px]">
                  ETB {item.price}
                </div>
                <div className="text-gray-500 text-[12px] truncate">
                  {item.category}
                </div>
              </div>
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProductAll;
